sql:
SELECT DISTINCT scientific_name
FROM species_observations
WHERE project_id = 123;

SELECT project_id, COUNT(*) AS total_observations
FROM species_observations
GROUP BY project_id;

SELECT site_id, COUNT(DISTINCT taxon_id) AS num_species
FROM species_observations
GROUP BY site_id;

SELECT observer_id, COUNT(observation_id) AS number_of_observations
FROM species_observations
GROUP BY observer_id;

SELECT observation_id, taxon_id, observation_method
FROM species_observations
WHERE project_id = 1;

SELECT taxon_id, COSH(AVG(location_precision)) AS avg_location_precision_cosh
FROM species_observations
GROUP BY taxon_id;

SELECT site_name, RANK() OVER (ORDER BY LENGTH(site_name) DESC) AS site_rank
FROM sites
WHERE site_code IS NOT NULL;

SELECT site_visits.visit_date, sites.site_name
FROM site_visits
INNER JOIN sites ON site_visits.site_id = sites.site_id;

external_knowledge:
- "garden" is a metaphor for "project";
- "diverse bouquet of floral species" represents "distinct species observed" (taxon_id);
- "vast" indicates the total count of different species observed.
